// =============================================================================
// Web search tool — uses the DuckDuckGo Instant Answer API (no key required)
// =============================================================================
static class WebSearch
{
    public static async Task<string> SearchAsync(HttpClient httpClient, string query)
    {
        Console.WriteLine($"  🔍 Searching: \"{query}\"");

        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
            var json = await httpClient.GetFromJsonAsync<JsonElement>(url);

            var findings = new List<string>();

            var abstractText = json.GetProperty("Abstract").GetString();
            var source = json.GetProperty("AbstractSource").GetString();
            var sourceUrl = json.GetProperty("AbstractURL").GetString();
            if (!string.IsNullOrWhiteSpace(abstractText))
            {
                findings.Add($"[{source}] {abstractText} (URL: {sourceUrl})");
            }

            if (json.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var topic in topics.EnumerateArray().Take(5))
                {
                    if (topic.TryGetProperty("Text", out var text) &&
                        topic.TryGetProperty("FirstURL", out var firstUrl) &&
                        !string.IsNullOrWhiteSpace(text.GetString()))
                    {
                        findings.Add($"- {text.GetString()} (URL: {firstUrl.GetString()})");
                    }
                }
            }

            var heading = json.GetProperty("Heading").GetString();
            if (findings.Count == 0 && !string.IsNullOrWhiteSpace(heading))
            {
                findings.Add($"Heading: {heading}");
            }

            return findings.Count > 0
                ? string.Join("\n", findings)
                : "No results found. Try a different or more specific search query.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try rephrasing the query.";
        }
    }
}

