    {
        Notes.Add(new Note(title, content));
        Console.WriteLine($"  📝 Note saved: \"{title}\"");
        return $"Note '{title}' saved successfully. You now have {Notes.Count} note(s).";
    }

    public string GetAllNotes()
    {
        if (Notes.Count == 0)
            return "No notes saved yet.";

        return string.Join("\n\n", Notes.Select((n, i) =>
            $"Note {i + 1} — [{n.Title}]\n{n.Content}"));
    }
}

